e(PHPExcel_Cell::stringFromColumnIndex($i).'4',$h);$rn=5;$n=1;foreach($rows as $r){$vals=array($n++,$r->employee_no,$r->personnel_no,$r->full_name,$r->gender,$r->employment_status,$r->employee_group,$r->employee_subgroup,$r->job_title_code.' - '.$r->job_title_name,$r->job_level,$r->department_code.' - '.$r->nm_dept,$r->structure_code.' - '.$r->structure_name,$r->manager_no.' - '.$r->manager_name,$r->hire_date,$r->probation_end_date,$r->termination_date,$r->cost_center_code.' - '.$r->cost_center_name,$r->profit_center_code.' - '.$r->profit_center_name,$r->payroll_area,$r->pay_grade,$r->work_location_type,$r->shift_code,$r->email,$r->phone,$r->city,$r->valid_from,$r->valid_to,$r->sap_reference,$r->updated_by?:$r->created_by);foreach($vals as $i=>$v)$sheet->setCellValue(PHPExcel_Cell::stringFromColumnIndex($i).$rn,$v);$rn++;}erpkb_excel_apply_standard_style($excel,array('sheet'=>$sheet,'title'=>erp_export_title('EMPLOYEE REPORT'),'header_row'=>4,'first_data_row'=>5,'last_data_row'=>max(5,$rn-1),'column_count'=>count($heads),'filters'=>array('As Of'=>erp_g('as_of_date',date('Y-m-d'))),'widths'=>array('B'=>16,'D'=>28,'I'=>28,'K'=>24,'L'=>26,'M'=>28,'Q'=>28,'R'=>28,'W'=>28)));$tmp=erpkb_excel_temp_file('employee_report_');PHPExcel_IOFactory::createWriter($excel,'Excel2007')->save($tmp);$size=@filesize($tmp);$sig=@file_get_contents($tmp,false,null,0,2);if(!$size||$sig!=='PK'){@unlink($tmp);while(ob_get_level()>$initial)ob_end_clean();echo erp_t('export_excel_invalid_file','File Excel gagal dibuat dengan benar.');exit;}while(ob_get_level()>$initial)ob_end_clean();header('Content-Type: application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');header('Content-Disposition: attachment; filename="employee_report_'.date('Ymd_His').'.xlsx"');header('Content-Length: '.$size);header('Cache-Control: max-age=0');header('Pragma: public');readfile($tmp);@unlink($tmp);exit;
